function xgbPredict(m, x) {
  if (!m || !m.t) return null;
  let sum = m.bs || 0;
  for (const tree of m.t) {
    let i = 0;
    while (i < tree.length) {
      const [f, thr, r, l] = tree[i];
      if (r === 0) { sum += l; break; }  // 리프 노드
      i = (x[f] < thr) ? i + 1 : r;
    }
  }
  return sum;
}
